sp_widget.client_script:
api.controller=function($scope) {
  /* widget controller */
  var c = this;

  c.total_spaces = $scope.data.total_spaces;
  c.total_available_spaces = $scope.data.total_available_spaces;
  c.workspace_type_count = $scope.data.workspace_type_count;
  c.workspace_summary_list = $scope.data.workspace_summary_list;
};

sp_widget.script:
(function() {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */

	var workspaceGr = new GlideRecord("x_1759267_wrm_workspace_options");
	workspaceGr.query();
	data.total_spaces = workspaceGr.getRowCount();

	var availableGr = new GlideRecord("x_1759267_wrm_workspace_options");
	availableGr.addQuery("status", "available");
	availableGr.query();
	data.total_available_spaces = availableGr.getRowCount();

	var agg = new GlideAggregate("x_1759267_wrm_workspace_options");
	agg.addAggregate("COUNT");
	agg.groupBy("workspace_type");
	agg.query();

	data.workspace_summary = {};
	data.workspace_type_count = agg.getRowCount();

	while (agg.next()) {
		var type = agg.getValue("workspace_type");
		var name = agg.getDisplayValue("workspace_type");
		var count = agg.getAggregate("COUNT");

		if (!data.workspace_summary[type]) {
			data.workspace_summary[type] = {};
		}

		data.workspace_summary[type].total = parseInt(count, 10);
		data.workspace_summary[type].name = name;
	}

	var availAgg = new GlideAggregate("x_1759267_wrm_workspace_options");
	availAgg.addQuery("status", "available");
	availAgg.addAggregate("COUNT");
	availAgg.groupBy("workspace_type");
	availAgg.query();

	while (availAgg.next()) {
		var _type = availAgg.getValue("workspace_type");
		var _name = availAgg.getDisplayValue("workspace_type");
		var _count = availAgg.getAggregate("COUNT");

		if (!data.workspace_summary[_type]) {
			data.workspace_summary[_type] = {};
		}

		data.workspace_summary[_type].available = parseInt(_count, 10);
		data.workspace_summary[_type].name = _name;
	}

	data.workspace_summary_list = [];

	for (type in data.workspace_summary) {
		var item = data.workspace_summary[type];

		data.workspace_summary_list.push({
			workspace_type: type,
			workspace_type_name: item.name,
			total: item.total || 0,
			available: item.available || 0
		});
	}

})();
